import React, { useState, useEffect, useMemo } from 'react';
import { useProducts } from './ProductContext';
import { useNavigate } from 'react-router-dom';
import { Mail, Lock, ShieldCheck, UserPlus, Trash2, Save, X, Pencil } from 'lucide-react';

const Admin = () => {
  const { staff, addStaff, updateStaff, deleteStaff, user, updateUser } = useProducts();
  const navigate = useNavigate();

  // Tahrirlash rejimi uchun state
  const [editingId, setEditingId] = useState(null);
  const [formData, setFormData] = useState({
    email: '',
    password: '',
    role: 'staff'
  });

  // Profil sozlamalari (faqat joriy foydalanuvchi uchun)
  const [profileData, setProfileData] = useState({
    email: '',
    password: '',
    role: ''
  });

  useEffect(() => {
    if (user) {
      setProfileData({
        email: user.email || '',
        password: user.password || '',
        role: user.role || ''
      });
    }
  }, [user]);

  // Tugma holatini tekshirish (Disabled logic)
  const isProfileChanged = useMemo(() => {
    if (!user) return false;
    const isDifferent = profileData.email !== user.email || 
                      profileData.password !== user.password || 
                      profileData.role !== user.role;
    const isNotEmpty = profileData.email.trim() !== '' && profileData.password.trim() !== '';
    return isDifferent && isNotEmpty;
  }, [profileData, user]);

  const isFormChanged = useMemo(() => {
    if (!editingId) {
      return formData.email.trim() !== '' && formData.password.trim() !== '';
    }
    const original = staff.find(s => s.id === editingId);
    if (!original) return false;

    const isDifferent = formData.email !== original.email || 
                      formData.password !== original.password || 
                      formData.role !== original.role;
    const isNotEmpty = formData.email.trim() !== '' && formData.password.trim() !== '';
    return isDifferent && isNotEmpty;
  }, [formData, editingId, staff]);

  // Handlers
  const handleProfileSave = (e) => {
    e.preventDefault();
    if (!profileData.email.includes('@')) return alert('Email xato!');

    updateUser(profileData);
    alert('Profil yangilandi!');
    if (profileData.role === 'staff') navigate('/products');
  };

  const handleStaffSubmit = (e) => {
    e.preventDefault();

    if (editingId) {
      // Tahrirlash
      updateStaff(editingId, formData);
      alert('Xodim ma\'lumotlari yangilandi!');
    } else {
      // Yangi qo'shish
      const success = addStaff(formData.email, formData.password, formData.role);
      if (!success) return;
      alert('Yangi xodim qo\'shildi!');
    }

    // Inputlarni tozalash va tahrirlash rejimidan chiqish
    resetForm();
  };

  const startEdit = (member) => {
    setEditingId(member.id);
    setFormData({
      email: member.email,
      password: member.password,
      role: member.role
    });
    // Scroll to form for better UX
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const resetForm = () => {
    setEditingId(null);
    setFormData({
      email: '',
      password: '',
      role: 'staff'
    });
  };

  return (
    <div className="p-6 max-w-5xl mx-auto space-y-10">
      {/* 1. Shaxsiy Profil Sozlamalari */}
      <div className="bg-white rounded-[2.5rem] p-8 shadow-md border border-gray-50">
        <div className="flex items-center gap-4 mb-8">
          <div className="p-3 bg-purple-100 rounded-2xl text-purple-700">
            <ShieldCheck className="w-8 h-8" />
          </div>
          <div>
            <h2 className="text-2xl font-black text-gray-900">Mening profilim</h2>
            <p className="text-gray-500 text-sm font-bold">Shaxsiy login ma'lumotlaringiz</p>
          </div>
        </div>

        <form onSubmit={handleProfileSave} className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="space-y-2">
            <label className="text-xs font-black text-gray-400 uppercase tracking-widest px-1">Email</label>
            <input
              type="email"
              value={profileData.email}
              onChange={(e) => setProfileData({...profileData, email: e.target.value})}
              className="w-full px-5 py-4 bg-slate-50 border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-purple-200 font-bold"
            />
          </div>
          <div className="space-y-2">
            <label className="text-xs font-black text-gray-400 uppercase tracking-widest px-1">Parol</label>
            <input
              type="password"
              value={profileData.password}
              onChange={(e) => setProfileData({...profileData, password: e.target.value})}
              className="w-full px-5 py-4 bg-slate-50 border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-purple-200 font-bold"
            />
          </div>
          <div className="space-y-2">
            <label className="text-xs font-black text-gray-400 uppercase tracking-widest px-1">Rol</label>
            <select
              value={profileData.role}
              onChange={(e) => setProfileData({...profileData, role: e.target.value})}
              className="w-full px-5 py-4 bg-slate-50 border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-purple-200 font-bold"
            >
              <option value="admin">Glavniy Admin</option>
              <option value="staff">Staff (Xodim)</option>
            </select>
          </div>
          <div className="md:col-span-3 flex justify-end">
            <button
              type="submit"
              disabled={!isProfileChanged}
              className={`flex items-center gap-2 px-8 py-4 rounded-2xl font-black transition-all ${
                isProfileChanged 
                ? 'bg-purple-700 text-white shadow-lg shadow-purple-200 hover:bg-purple-800 active:scale-95' 
                : 'bg-gray-200 text-gray-400 cursor-not-allowed'
              }`}
            >
              <Save className="w-5 h-5" /> Saqlash
            </button>
          </div>
        </form>
      </div>

      <hr className="border-gray-100" />

      {/* 2. Xodimlarni Boshqarish (Add/Edit) */}
      <div>
        <div className="flex items-center gap-4 mb-8">
          <div className="p-3 bg-blue-100 rounded-2xl text-blue-700">
            {editingId ? <Pencil className="w-8 h-8" /> : <UserPlus className="w-8 h-8" />}
          </div>
          <div>
            <h2 className="text-2xl font-black text-gray-900">
              {editingId ? 'Xodimni tahrirlash' : 'Yangi xodim qo\'shish'}
            </h2>
            <p className="text-gray-500 text-sm font-bold">Tizimga kirish huquqini boshqarish</p>
          </div>
        </div>

        <form onSubmit={handleStaffSubmit} className="bg-white p-8 rounded-[2.5rem] shadow-md border border-gray-50 mb-10">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="space-y-2">
              <label className="text-xs font-black text-gray-400 uppercase tracking-widest px-1">Email</label>
              <input
                type="email"
                required
                value={formData.email}
                onChange={(e) => setFormData({...formData, email: e.target.value})}
                className="w-full px-5 py-4 bg-slate-50 border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-blue-200 font-bold"
                placeholder="xodim@gmail.com"
              />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-black text-gray-400 uppercase tracking-widest px-1">Parol</label>
              <input
                type="password"
                required
                value={formData.password}
                onChange={(e) => setFormData({...formData, password: e.target.value})}
                className="w-full px-5 py-4 bg-slate-50 border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-blue-200 font-bold"
                placeholder="******"
              />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-black text-gray-400 uppercase tracking-widest px-1">Rol</label>
              <select
                value={formData.role}
                onChange={(e) => setFormData({...formData, role: e.target.value})}
                className="w-full px-5 py-4 bg-slate-50 border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-blue-200 font-bold"
              >
                <option value="staff">Staff (Xodim)</option>
                <option value="admin">Admin</option>
              </select>
            </div>
          </div>

          <div className="flex gap-4 mt-8">
            {editingId && (
              <button
                type="button"
                onClick={resetForm}
                className="flex-1 py-4 bg-gray-100 text-gray-600 rounded-2xl font-black text-lg hover:bg-gray-200 transition-all flex items-center justify-center gap-2"
              >
                <X className="w-5 h-5" /> Bekor qilish
              </button>
            )}
            <button
              type="submit"
              disabled={!isFormChanged}
              className={`flex-[2] py-4 rounded-2xl font-black text-lg transition-all flex items-center justify-center gap-2 ${
                isFormChanged 
                ? 'bg-blue-600 text-white shadow-lg shadow-blue-100 hover:bg-blue-700 active:scale-95' 
                : 'bg-gray-200 text-gray-400 cursor-not-allowed'
              }`}
            >
              <Save className="w-6 h-6" /> 
              {editingId ? 'O\'zgarishlarni saqlash' : 'Xodimni saqlash'}
            </button>
          </div>
        </form>

        <div className="bg-white rounded-[2.5rem] shadow-md overflow-hidden border border-gray-50">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b border-gray-100">
              <tr>
                <th className="px-8 py-5 text-xs font-black text-gray-400 uppercase tracking-widest">Email</th>
                <th className="px-8 py-5 text-xs font-black text-gray-400 uppercase tracking-widest">Rol</th>
                <th className="px-8 py-5 text-xs font-black text-gray-400 uppercase tracking-widest text-right">Amallar</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {staff.length === 0 ? (
                <tr>
                  <td colSpan="3" className="px-8 py-10 text-center text-gray-400 font-bold">Xodimlar mavjud emas</td>
                </tr>
              ) : (
                staff.map((member) => (
                  <tr 
                    key={member.id} 
                    className={`hover:bg-blue-50/50 transition-colors cursor-pointer group ${editingId === member.id ? 'bg-blue-50' : ''}`}
                    onClick={() => startEdit(member)}
                  >
                    <td className="px-8 py-5 font-bold text-gray-700">{member.email}</td>
                    <td className="px-8 py-5">
                      <span className={`px-4 py-1.5 rounded-full text-xs font-black uppercase tracking-tighter ${
                        member.role === 'admin' ? 'bg-purple-100 text-purple-700' : 'bg-blue-100 text-blue-700'
                      }`}>
                        {member.role}
                      </span>
                    </td>
                    <td className="px-8 py-5 text-right">
                      <div className="flex justify-end gap-2">
                        <button
                          onClick={(e) => { e.stopPropagation(); startEdit(member); }}
                          className="text-gray-300 hover:text-blue-600 transition-colors p-2"
                        >
                          <Pencil className="w-5 h-5" />
                        </button>
                        <button
                          onClick={(e) => { e.stopPropagation(); deleteStaff(member.id); }}
                          className="text-gray-300 hover:text-red-600 transition-colors p-2"
                        >
                          <Trash2 className="w-5 h-5" />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Admin;
